const OrderBtn=document.querySelector(".cart-summary__checkout");OrderBtn&&OrderBtn.addEventListener("click",async e=>{try{const e=await fetch("../back/router.php?action=add-order",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()}}),t=await e.json();t.success?(showNotification("Commande validée","green"),setTimeout(()=>window.location.href="../back/router.php?action=profile-view",2e3)):showNotification(t.message,"red")}catch(e){console.error(e)}});